import pandas as pd

DTYPES = {
    # optional: "age": "float64",
    # optional: "country_US": "int64",
}

def prepare_features(df_infer: pd.DataFrame, FEATURES, dtypes=None):
    dtypes = dtypes or {}

    missing = [c for c in FEATURES if c not in df_infer.columns]
    if missing:
        raise ValueError(f"Missing required features: {missing}")

    X = df_infer.loc[:, FEATURES].copy()  # drops extras + enforces order

    # Optional strict dtype enforcement
    for col, dt in dtypes.items():
        if col in X.columns:
            X[col] = X[col].astype(dt)

    return X
```

This ensures schema parity by selecting `FEATURES` in order and failing fast on missing columns.

