```python
import pandas as pd
import operator

def filter_dataframe(df: pd.DataFrame, column: str, value, op: str = "==", na_policy: str = "drop"):
    ops = {
        "==": operator.eq,
        "!=": operator.ne,
        ">": operator.gt,
        ">=": operator.ge,
        "<": operator.lt,
        "<=": operator.le,
    }

    if column not in df.columns:
        raise ValueError(f"Column '{column}' not found in DataFrame.")
    if op not in ops:
        raise ValueError(f"Unsupported operator '{op}'. Choose from {list(ops.keys())}.")
    if na_policy not in {"keep", "drop", "fail"}:
        raise ValueError("na_policy must be one of: 'keep', 'drop', 'fail'")

    s = df[column]
    na_mask = s.isna()

    if na_policy == "fail" and na_mask.any():
        raise ValueError(f"Column '{column}' contains NaN values")

    comp_mask = ops[op](s, value)

    if na_policy == "keep":
        mask = comp_mask | na_mask
    else:  # "drop" (or "fail" with no NaNs)
        mask = comp_mask & ~na_mask

    return df[mask]
```

