import pandas as pd

def select_df(df, rows, cols):
    # Treat non-list-like scalars (e.g., a single string/Timestamp) as one-element lists
    if not isinstance(rows, (list, tuple, pd.Index)):
        rows = [rows]
    if not isinstance(cols, (list, tuple, pd.Index)):
        cols = [cols]
    return df.loc[rows, cols]
